from pathlib import Path
from datetime import datetime

APP_CODE = 'import os\nimport re\nimport shutil\nfrom datetime import date, datetime\n\nimport pandas as pd\nimport streamlit as st\n\n# =========================\n# CONFIGURAÇÃO INICIAL\n# =========================\n\nst.set_page_config(\n    page_title="Sistema de Cotações Marialva",\n    page_icon="🛒",\n    layout="wide"\n)\n\nPASTA_DADOS = "dados"\nPASTA_BACKUPS = "backups"\n\nARQUIVOS = {\n    "produtos": os.path.join(PASTA_DADOS, "produtos.csv"),\n    "fornecedores": os.path.join(PASTA_DADOS, "fornecedores.csv"),\n    "cotacoes": os.path.join(PASTA_DADOS, "cotacoes.csv"),\n    "itens_cotacao": os.path.join(PASTA_DADOS, "itens_cotacao.csv"),\n    "respostas": os.path.join(PASTA_DADOS, "respostas.csv"),\n}\n\nCOLUNAS = {\n    "produtos": ["ProdutoID", "Produto", "Marca", "Tamanho", "Categoria", "Unidade", "Ativo", "Observacao"],\n    "fornecedores": ["FornecedorID", "Vendedor", "Empresa", "WhatsApp", "CategoriaForte", "Ativo", "Observacao"],\n    "cotacoes": ["CotacaoID", "Data", "Prazo", "Status", "Responsavel", "Observacao"],\n    "itens_cotacao": ["ItemID", "CotacaoID", "ProdutoID", "QuantidadeDesejada", "Observacao"],\n    "respostas": ["RespostaID", "CotacaoID", "FornecedorID", "ProdutoID", "Preco", "TemProduto", "Observacao"],\n}\n\nCATEGORIAS = ["Mercearia", "Limpeza", "Higiene", "Bebidas", "Frios", "Padaria", "Hortifruti", "Outros"]\nUNIDADES = ["Unidade", "Caixa", "Fardo", "Pacote", "Kg", "Litro", "Sachê", "Lata"]\nSTATUS_COTACAO = ["Aberta", "Aguardando respostas", "Parcialmente respondida", "Finalizada", "Pedido gerado", "Cancelada", "Histórica importada"]\n\n\ndef criar_arquivos_iniciais():\n    os.makedirs(PASTA_DADOS, exist_ok=True)\n    os.makedirs(PASTA_BACKUPS, exist_ok=True)\n\n    for nome, caminho in ARQUIVOS.items():\n        if not os.path.exists(caminho):\n            df = pd.DataFrame(columns=COLUNAS[nome])\n            df.to_csv(caminho, index=False, encoding="utf-8-sig")\n\n\ndef carregar(nome):\n    caminho = ARQUIVOS[nome]\n    colunas = COLUNAS[nome]\n\n    if not os.path.exists(caminho):\n        return pd.DataFrame(columns=colunas)\n\n    df = pd.read_csv(caminho, encoding="utf-8-sig", dtype=str, keep_default_na=False)\n\n    for coluna in colunas:\n        if coluna not in df.columns:\n            df[coluna] = ""\n\n    return df[colunas]\n\n\ndef salvar(nome, df):\n    colunas = COLUNAS[nome]\n    df = df.copy()\n\n    for coluna in colunas:\n        if coluna not in df.columns:\n            df[coluna] = ""\n\n    df = df[colunas]\n    df.to_csv(ARQUIVOS[nome], index=False, encoding="utf-8-sig")\n\n\ndef fazer_backup_manual():\n    timestamp = datetime.now().strftime("%Y-%m-%d_%H-%M-%S")\n    pasta_destino = os.path.join(PASTA_BACKUPS, f"backup_{timestamp}")\n    os.makedirs(pasta_destino, exist_ok=True)\n\n    for nome, caminho in ARQUIVOS.items():\n        if os.path.exists(caminho):\n            shutil.copy2(caminho, os.path.join(pasta_destino, os.path.basename(caminho)))\n\n    return pasta_destino\n\n\ndef gerar_id(prefixo, df, coluna_id):\n    if df.empty or coluna_id not in df.columns:\n        numero = 1\n    else:\n        ids = df[coluna_id].astype(str).str.replace(prefixo, "", regex=False)\n        ids = pd.to_numeric(ids, errors="coerce").dropna()\n        numero = int(ids.max()) + 1 if not ids.empty else 1\n\n    return f"{prefixo}{numero:03d}"\n\n\ndef texto(valor):\n    if valor is None:\n        return ""\n    valor = str(valor)\n    if valor.lower() == "nan":\n        return ""\n    return valor\n\n\ndef moeda(valor):\n    try:\n        return f"R$ {float(valor):,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")\n    except Exception:\n        return ""\n\n\ndef preco_para_float(valor):\n    if valor is None:\n        return None\n\n    valor = str(valor).strip().upper()\n    valor = valor.replace("R$", "").replace(" ", "")\n\n    if valor in ["", "NT", "N/T", "NAO", "NÃO", "N", "SEM", "SEMESTOQUE"]:\n        return None\n\n    valor = re.sub(r"[^0-9,.-]", "", valor)\n\n    if "," in valor and "." in valor:\n        valor = valor.replace(".", "").replace(",", ".")\n    elif "," in valor:\n        valor = valor.replace(",", ".")\n\n    try:\n        return float(valor)\n    except Exception:\n        return None\n\n\ndef descricao_produto(row):\n    partes = [texto(row.get("Produto")), texto(row.get("Marca")), texto(row.get("Tamanho"))]\n    return " ".join([p for p in partes if p]).strip()\n\n\ndef adicionar_descricao_produtos(df_produtos):\n    df = df_produtos.copy()\n    if df.empty:\n        df["DescricaoCompleta"] = []\n        return df\n\n    df["DescricaoCompleta"] = df.apply(\n        lambda row: f"{row[\'ProdutoID\']} - {descricao_produto(row)}", axis=1\n    )\n    return df\n\n\ndef upsert_resposta(df_respostas, cotacao_id, fornecedor_id, produto_id, preco, tem_produto, observacao=""):\n    df = df_respostas.copy()\n    mascara = (\n        (df["CotacaoID"].astype(str) == str(cotacao_id))\n        & (df["FornecedorID"].astype(str) == str(fornecedor_id))\n        & (df["ProdutoID"].astype(str) == str(produto_id))\n    )\n\n    preco_final = "" if tem_produto == "Não" or preco is None else str(float(preco))\n\n    if mascara.any():\n        idx = df[mascara].index[0]\n        df.loc[idx, "Preco"] = preco_final\n        df.loc[idx, "TemProduto"] = tem_produto\n        df.loc[idx, "Observacao"] = observacao\n        acao = "atualizada"\n    else:\n        novo_id = gerar_id("RESP", df, "RespostaID")\n        novo = pd.DataFrame([{\n            "RespostaID": novo_id,\n            "CotacaoID": cotacao_id,\n            "FornecedorID": fornecedor_id,\n            "ProdutoID": produto_id,\n            "Preco": preco_final,\n            "TemProduto": tem_produto,\n            "Observacao": observacao,\n        }])\n        df = pd.concat([df, novo], ignore_index=True)\n        acao = "criada"\n\n    return df, acao\n\n\ndef preparar_comparativo(df_respostas, df_produtos, df_fornecedores, cotacao_id=None):\n    if df_respostas.empty:\n        return pd.DataFrame()\n\n    df = df_respostas.copy()\n    if cotacao_id:\n        df = df[df["CotacaoID"].astype(str) == str(cotacao_id)]\n\n    df["Preco"] = df["Preco"].apply(preco_para_float)\n    df = df[df["TemProduto"].astype(str) == "Sim"]\n    df = df.dropna(subset=["Preco"])\n\n    if df.empty:\n        return pd.DataFrame()\n\n    df = df.merge(df_produtos, on="ProdutoID", how="left")\n    df = df.merge(df_fornecedores, on="FornecedorID", how="left")\n\n    idx_menores = df.groupby("ProdutoID")["Preco"].idxmin()\n    vencedores = df.loc[idx_menores].copy()\n\n    maiores = df.groupby("ProdutoID")["Preco"].max().reset_index().rename(columns={"Preco": "MaiorPreco"})\n    qtd = df.groupby("ProdutoID")["FornecedorID"].nunique().reset_index().rename(columns={"FornecedorID": "QtdFornecedores"})\n\n    vencedores = vencedores.merge(maiores, on="ProdutoID", how="left")\n    vencedores = vencedores.merge(qtd, on="ProdutoID", how="left")\n    vencedores["EconomiaUnitaria"] = vencedores["MaiorPreco"] - vencedores["Preco"]\n    vencedores["DescricaoProduto"] = vencedores.apply(descricao_produto, axis=1)\n\n    resultado = vencedores[[\n        "CotacaoID",\n        "ProdutoID",\n        "DescricaoProduto",\n        "Categoria",\n        "Vendedor",\n        "FornecedorID",\n        "Preco",\n        "MaiorPreco",\n        "EconomiaUnitaria",\n        "QtdFornecedores",\n    ]].rename(columns={\n        "Vendedor": "FornecedorVencedor",\n        "Preco": "MenorPreco",\n    })\n\n    return resultado.sort_values(["FornecedorVencedor", "DescricaoProduto"])\n\n\ndef formatar_tabela_moeda(df, colunas):\n    df = df.copy()\n    for coluna in colunas:\n        if coluna in df.columns:\n            df[coluna] = df[coluna].apply(moeda)\n    return df\n\n\ncriar_arquivos_iniciais()\n\nprodutos = carregar("produtos")\nfornecedores = carregar("fornecedores")\ncotacoes = carregar("cotacoes")\nitens = carregar("itens_cotacao")\nrespostas = carregar("respostas")\n\n# =========================\n# TÍTULO E MENU\n# =========================\n\nst.title("🛒 Sistema de Cotações — Supermercado Marialva")\nst.caption("Protótipo inicial em Python + Streamlit")\n\nmenu = st.sidebar.radio(\n    "Menu",\n    [\n        "Dashboard",\n        "Cadastro de Produtos",\n        "Cadastro de Fornecedores",\n        "Criar Cotação",\n        "Itens da Cotação",\n        "Mensagem WhatsApp",\n        "Lançar Respostas",\n        "Importar Resposta WhatsApp",\n        "Comparativo",\n        "Pedido Final",\n        "Backups",\n        "Ver Bases",\n    ]\n)\n\n# =========================\n# DASHBOARD\n# =========================\n\nif menu == "Dashboard":\n    st.header("📊 Dashboard Geral")\n\n    col1, col2, col3, col4 = st.columns(4)\n    col1.metric("Produtos cadastrados", len(produtos))\n    col2.metric("Fornecedores cadastrados", len(fornecedores))\n    col3.metric("Cotações criadas", len(cotacoes))\n    col4.metric("Respostas lançadas", len(respostas))\n\n    st.divider()\n\n    comparativo_geral = preparar_comparativo(respostas, produtos, fornecedores)\n    if not comparativo_geral.empty:\n        col5, col6 = st.columns(2)\n        col5.metric("Itens com vencedor", len(comparativo_geral))\n        col6.metric("Economia potencial unitária", moeda(comparativo_geral["EconomiaUnitaria"].sum()))\n\n        st.subheader("Fornecedores que mais venceram")\n        resumo = comparativo_geral.groupby("FornecedorVencedor").size().reset_index(name="Qtd de vitórias")\n        resumo = resumo.sort_values("Qtd de vitórias", ascending=False)\n        st.dataframe(resumo, use_container_width=True)\n\n    st.subheader("Últimas cotações")\n    if cotacoes.empty:\n        st.info("Nenhuma cotação criada ainda.")\n    else:\n        st.dataframe(cotacoes.tail(10), use_container_width=True)\n\n# =========================\n# CADASTRO DE PRODUTOS\n# =========================\n\nelif menu == "Cadastro de Produtos":\n    st.header("📦 Cadastro de Produtos")\n\n    aba_produtos = st.tabs(["Cadastrar", "Editar / Excluir", "Visualizar"])\n\n    with aba_produtos[0]:\n        st.subheader("Cadastrar novo produto")\n        with st.form("form_produto"):\n            col1, col2, col3 = st.columns(3)\n\n            with col1:\n                produto = st.text_input("Produto", placeholder="Ex: Atum sólido")\n                marca = st.text_input("Marca", placeholder="Ex: Coqueiro")\n\n            with col2:\n                tamanho = st.text_input("Tamanho", placeholder="Ex: 170g")\n                categoria = st.selectbox("Categoria", CATEGORIAS)\n\n            with col3:\n                unidade = st.selectbox("Unidade", UNIDADES)\n                observacao = st.text_input("Observação")\n\n            salvar_produto = st.form_submit_button("Salvar produto")\n\n            if salvar_produto:\n                if not produto.strip():\n                    st.error("Informe o nome do produto.")\n                else:\n                    novo_id = gerar_id("PROD", produtos, "ProdutoID")\n                    novo = pd.DataFrame([{\n                        "ProdutoID": novo_id,\n                        "Produto": produto.strip(),\n                        "Marca": marca.strip(),\n                        "Tamanho": tamanho.strip(),\n                        "Categoria": categoria,\n                        "Unidade": unidade,\n                        "Ativo": "Sim",\n                        "Observacao": observacao.strip(),\n                    }])\n                    produtos = pd.concat([produtos, novo], ignore_index=True)\n                    salvar("produtos", produtos)\n                    st.success(f"Produto cadastrado com sucesso: {novo_id}")\n                    st.rerun()\n\n    with aba_produtos[1]:\n        st.subheader("Editar ou excluir produto")\n        if produtos.empty:\n            st.info("Nenhum produto cadastrado ainda.")\n        else:\n            produtos_desc = adicionar_descricao_produtos(produtos)\n            escolha = st.selectbox("Escolha o produto", produtos_desc["DescricaoCompleta"].tolist())\n            produto_id = escolha.split(" - ")[0]\n            linha = produtos[produtos["ProdutoID"] == produto_id].index[0]\n            dados = produtos.loc[linha]\n\n            with st.form("form_editar_produto"):\n                col1, col2, col3 = st.columns(3)\n                with col1:\n                    novo_produto = st.text_input("Produto", value=texto(dados["Produto"]))\n                    nova_marca = st.text_input("Marca", value=texto(dados["Marca"]))\n                with col2:\n                    novo_tamanho = st.text_input("Tamanho", value=texto(dados["Tamanho"]))\n                    categoria_atual = texto(dados["Categoria"])\n                    nova_categoria = st.selectbox("Categoria", CATEGORIAS, index=CATEGORIAS.index(categoria_atual) if categoria_atual in CATEGORIAS else 0)\n                with col3:\n                    unidade_atual = texto(dados["Unidade"])\n                    nova_unidade = st.selectbox("Unidade", UNIDADES, index=UNIDADES.index(unidade_atual) if unidade_atual in UNIDADES else 0)\n                    ativo_atual = texto(dados["Ativo"])\n                    novo_ativo = st.selectbox("Ativo", ["Sim", "Não"], index=0 if ativo_atual != "Não" else 1)\n\n                nova_observacao = st.text_input("Observação", value=texto(dados["Observacao"]))\n\n                col_a, col_b = st.columns(2)\n                atualizar = col_a.form_submit_button("Atualizar produto")\n                excluir = col_b.form_submit_button("Excluir produto")\n\n                if atualizar:\n                    produtos.loc[linha, "Produto"] = novo_produto.strip()\n                    produtos.loc[linha, "Marca"] = nova_marca.strip()\n                    produtos.loc[linha, "Tamanho"] = novo_tamanho.strip()\n                    produtos.loc[linha, "Categoria"] = nova_categoria\n                    produtos.loc[linha, "Unidade"] = nova_unidade\n                    produtos.loc[linha, "Ativo"] = novo_ativo\n                    produtos.loc[linha, "Observacao"] = nova_observacao.strip()\n                    salvar("produtos", produtos)\n                    st.success("Produto atualizado com sucesso.")\n                    st.rerun()\n\n                if excluir:\n                    usado = (\n                        (itens["ProdutoID"].astype(str) == produto_id).any()\n                        or (respostas["ProdutoID"].astype(str) == produto_id).any()\n                    )\n                    if usado:\n                        produtos.loc[linha, "Ativo"] = "Não"\n                        salvar("produtos", produtos)\n                        st.warning("Este produto já tem histórico. Por segurança, ele foi desativado em vez de apagado.")\n                    else:\n                        produtos = produtos.drop(index=linha).reset_index(drop=True)\n                        salvar("produtos", produtos)\n                        st.success("Produto excluído com sucesso.")\n                    st.rerun()\n\n    with aba_produtos[2]:\n        st.subheader("Produtos cadastrados")\n        busca = st.text_input("Buscar produto, marca ou categoria")\n        visual = produtos.copy()\n        if busca.strip():\n            termo = busca.strip().lower()\n            visual = visual[visual.apply(lambda row: termo in " ".join(row.astype(str)).lower(), axis=1)]\n        st.dataframe(visual, use_container_width=True)\n\n# =========================\n# CADASTRO DE FORNECEDORES\n# =========================\n\nelif menu == "Cadastro de Fornecedores":\n    st.header("🚚 Cadastro de Fornecedores")\n\n    aba_fornecedores = st.tabs(["Cadastrar", "Editar / Excluir", "Visualizar"])\n\n    with aba_fornecedores[0]:\n        st.subheader("Cadastrar novo fornecedor")\n        with st.form("form_fornecedor"):\n            col1, col2 = st.columns(2)\n            with col1:\n                vendedor = st.text_input("Nome do vendedor", placeholder="Ex: Marcio")\n                empresa = st.text_input("Empresa")\n                whatsapp = st.text_input("WhatsApp")\n            with col2:\n                categoria_forte = st.text_input("Categoria forte", placeholder="Ex: Mercearia")\n                observacao = st.text_input("Observação")\n\n            salvar_fornecedor = st.form_submit_button("Salvar fornecedor")\n\n            if salvar_fornecedor:\n                if not vendedor.strip():\n                    st.error("Informe o nome do vendedor.")\n                else:\n                    novo_id = gerar_id("FOR", fornecedores, "FornecedorID")\n                    novo = pd.DataFrame([{\n                        "FornecedorID": novo_id,\n                        "Vendedor": vendedor.strip(),\n                        "Empresa": empresa.strip(),\n                        "WhatsApp": whatsapp.strip(),\n                        "CategoriaForte": categoria_forte.strip(),\n                        "Ativo": "Sim",\n                        "Observacao": observacao.strip(),\n                    }])\n                    fornecedores = pd.concat([fornecedores, novo], ignore_index=True)\n                    salvar("fornecedores", fornecedores)\n                    st.success(f"Fornecedor cadastrado com sucesso: {novo_id}")\n                    st.rerun()\n\n    with aba_fornecedores[1]:\n        st.subheader("Editar ou excluir fornecedor")\n        if fornecedores.empty:\n            st.info("Nenhum fornecedor cadastrado ainda.")\n        else:\n            fornecedores_desc = fornecedores.copy()\n            fornecedores_desc["Descricao"] = fornecedores_desc["FornecedorID"].astype(str) + " - " + fornecedores_desc["Vendedor"].astype(str)\n            escolha = st.selectbox("Escolha o fornecedor", fornecedores_desc["Descricao"].tolist())\n            fornecedor_id = escolha.split(" - ")[0]\n            linha = fornecedores[fornecedores["FornecedorID"] == fornecedor_id].index[0]\n            dados = fornecedores.loc[linha]\n\n            with st.form("form_editar_fornecedor"):\n                col1, col2 = st.columns(2)\n                with col1:\n                    novo_vendedor = st.text_input("Vendedor", value=texto(dados["Vendedor"]))\n                    nova_empresa = st.text_input("Empresa", value=texto(dados["Empresa"]))\n                    novo_whatsapp = st.text_input("WhatsApp", value=texto(dados["WhatsApp"]))\n                with col2:\n                    nova_categoria = st.text_input("Categoria forte", value=texto(dados["CategoriaForte"]))\n                    ativo_atual = texto(dados["Ativo"])\n                    novo_ativo = st.selectbox("Ativo", ["Sim", "Não"], index=0 if ativo_atual != "Não" else 1)\n                    nova_observacao = st.text_input("Observação", value=texto(dados["Observacao"]))\n\n                col_a, col_b = st.columns(2)\n                atualizar = col_a.form_submit_button("Atualizar fornecedor")\n                excluir = col_b.form_submit_button("Excluir fornecedor")\n\n                if atualizar:\n                    fornecedores.loc[linha, "Vendedor"] = novo_vendedor.strip()\n                    fornecedores.loc[linha, "Empresa"] = nova_empresa.strip()\n                    fornecedores.loc[linha, "WhatsApp"] = novo_whatsapp.strip()\n                    fornecedores.loc[linha, "CategoriaForte"] = nova_categoria.strip()\n                    fornecedores.loc[linha, "Ativo"] = novo_ativo\n                    fornecedores.loc[linha, "Observacao"] = nova_observacao.strip()\n                    salvar("fornecedores", fornecedores)\n                    st.success("Fornecedor atualizado com sucesso.")\n                    st.rerun()\n\n                if excluir:\n                    usado = respostas["FornecedorID"].astype(str).eq(fornecedor_id).any()\n                    if usado:\n                        fornecedores.loc[linha, "Ativo"] = "Não"\n                        salvar("fornecedores", fornecedores)\n                        st.warning("Este fornecedor já tem histórico. Por segurança, ele foi desativado em vez de apagado.")\n                    else:\n                        fornecedores = fornecedores.drop(index=linha).reset_index(drop=True)\n                        salvar("fornecedores", fornecedores)\n                        st.success("Fornecedor excluído com sucesso.")\n                    st.rerun()\n\n    with aba_fornecedores[2]:\n        st.subheader("Fornecedores cadastrados")\n        busca = st.text_input("Buscar fornecedor, empresa ou telefone")\n        visual = fornecedores.copy()\n        if busca.strip():\n            termo = busca.strip().lower()\n            visual = visual[visual.apply(lambda row: termo in " ".join(row.astype(str)).lower(), axis=1)]\n        st.dataframe(visual, use_container_width=True)\n\n# =========================\n# CRIAR COTAÇÃO\n# =========================\n\nelif menu == "Criar Cotação":\n    st.header("📝 Criar Cotação")\n\n    aba_cotacao = st.tabs(["Criar", "Editar status", "Visualizar"])\n\n    with aba_cotacao[0]:\n        with st.form("form_cotacao"):\n            col1, col2, col3 = st.columns(3)\n            with col1:\n                data_cotacao = st.date_input("Data", value=date.today())\n            with col2:\n                prazo = st.text_input("Prazo de resposta", placeholder="Ex: Hoje até 15h")\n            with col3:\n                responsavel = st.text_input("Responsável", value="João")\n            observacao = st.text_input("Observação", placeholder="Ex: Cotação de mercearia")\n\n            salvar_cotacao = st.form_submit_button("Criar cotação")\n\n            if salvar_cotacao:\n                novo_id = gerar_id("COT", cotacoes, "CotacaoID")\n                novo = pd.DataFrame([{\n                    "CotacaoID": novo_id,\n                    "Data": str(data_cotacao),\n                    "Prazo": prazo.strip(),\n                    "Status": "Aberta",\n                    "Responsavel": responsavel.strip(),\n                    "Observacao": observacao.strip(),\n                }])\n                cotacoes = pd.concat([cotacoes, novo], ignore_index=True)\n                salvar("cotacoes", cotacoes)\n                st.success(f"Cotação criada com sucesso: {novo_id}")\n                st.rerun()\n\n    with aba_cotacao[1]:\n        if cotacoes.empty:\n            st.info("Nenhuma cotação criada ainda.")\n        else:\n            cotacao_escolhida = st.selectbox("Escolha a cotação", cotacoes["CotacaoID"].tolist())\n            linha = cotacoes[cotacoes["CotacaoID"] == cotacao_escolhida].index[0]\n            dados = cotacoes.loc[linha]\n\n            with st.form("form_editar_cotacao"):\n                novo_prazo = st.text_input("Prazo", value=texto(dados["Prazo"]))\n                status_atual = texto(dados["Status"])\n                novo_status = st.selectbox("Status", STATUS_COTACAO, index=STATUS_COTACAO.index(status_atual) if status_atual in STATUS_COTACAO else 0)\n                novo_responsavel = st.text_input("Responsável", value=texto(dados["Responsavel"]))\n                nova_observacao = st.text_input("Observação", value=texto(dados["Observacao"]))\n\n                atualizar = st.form_submit_button("Atualizar cotação")\n                if atualizar:\n                    cotacoes.loc[linha, "Prazo"] = novo_prazo.strip()\n                    cotacoes.loc[linha, "Status"] = novo_status\n                    cotacoes.loc[linha, "Responsavel"] = novo_responsavel.strip()\n                    cotacoes.loc[linha, "Observacao"] = nova_observacao.strip()\n                    salvar("cotacoes", cotacoes)\n                    st.success("Cotação atualizada com sucesso.")\n                    st.rerun()\n\n    with aba_cotacao[2]:\n        st.subheader("Cotações")\n        st.dataframe(cotacoes, use_container_width=True)\n\n# =========================\n# ITENS DA COTAÇÃO\n# =========================\n\nelif menu == "Itens da Cotação":\n    st.header("📋 Itens da Cotação")\n\n    if cotacoes.empty:\n        st.warning("Crie uma cotação primeiro.")\n    elif produtos.empty:\n        st.warning("Cadastre produtos primeiro.")\n    else:\n        cotacao_escolhida = st.selectbox("Escolha a cotação", cotacoes["CotacaoID"].tolist())\n        produtos_ativos = produtos[produtos["Ativo"].astype(str) != "Não"].copy()\n        produtos_desc = adicionar_descricao_produtos(produtos_ativos)\n\n        st.subheader("Adicionar item")\n        with st.form("form_item_cotacao"):\n            produto_escolhido = st.selectbox("Escolha o produto", produtos_desc["DescricaoCompleta"].tolist())\n            produto_id = produto_escolhido.split(" - ")[0]\n            quantidade = st.number_input("Quantidade desejada", min_value=0, step=1)\n            observacao = st.text_input("Observação do item")\n            adicionar = st.form_submit_button("Adicionar item à cotação")\n\n            if adicionar:\n                ja_existe = ((itens["CotacaoID"] == cotacao_escolhida) & (itens["ProdutoID"] == produto_id)).any()\n                if ja_existe:\n                    st.warning("Este produto já está nesta cotação.")\n                else:\n                    novo_id = gerar_id("ITEM", itens, "ItemID")\n                    novo = pd.DataFrame([{\n                        "ItemID": novo_id,\n                        "CotacaoID": cotacao_escolhida,\n                        "ProdutoID": produto_id,\n                        "QuantidadeDesejada": str(quantidade),\n                        "Observacao": observacao.strip(),\n                    }])\n                    itens = pd.concat([itens, novo], ignore_index=True)\n                    salvar("itens_cotacao", itens)\n                    st.success("Item adicionado à cotação.")\n                    st.rerun()\n\n        st.divider()\n        st.subheader("Itens cadastrados na cotação")\n        itens_filtrados = itens[itens["CotacaoID"] == cotacao_escolhida].copy()\n\n        if itens_filtrados.empty:\n            st.info("Nenhum item adicionado ainda.")\n        else:\n            itens_com_produtos = itens_filtrados.merge(produtos, on="ProdutoID", how="left")\n            itens_com_produtos["DescricaoProduto"] = itens_com_produtos.apply(descricao_produto, axis=1)\n            st.dataframe(itens_com_produtos[["ItemID", "CotacaoID", "ProdutoID", "DescricaoProduto", "QuantidadeDesejada", "Observacao_x"]], use_container_width=True)\n\n            remover_item = st.selectbox("Remover item da cotação", itens_com_produtos["ItemID"].tolist())\n            if st.button("Remover item selecionado"):\n                itens = itens[itens["ItemID"] != remover_item].reset_index(drop=True)\n                salvar("itens_cotacao", itens)\n                st.success("Item removido da cotação.")\n                st.rerun()\n\n# =========================\n# MENSAGEM WHATSAPP\n# =========================\n\nelif menu == "Mensagem WhatsApp":\n    st.header("📲 Mensagem para WhatsApp")\n\n    if cotacoes.empty:\n        st.warning("Crie uma cotação primeiro.")\n    elif fornecedores.empty:\n        st.warning("Cadastre fornecedores primeiro.")\n    elif itens.empty:\n        st.warning("Adicione itens à cotação primeiro.")\n    else:\n        cotacao_escolhida = st.selectbox("Cotação", cotacoes["CotacaoID"].tolist())\n        fornecedores_ativos = fornecedores[fornecedores["Ativo"].astype(str) != "Não"].copy()\n        fornecedores_ativos["Descricao"] = fornecedores_ativos["FornecedorID"].astype(str) + " - " + fornecedores_ativos["Vendedor"].astype(str)\n        fornecedor_escolhido = st.selectbox("Fornecedor", fornecedores_ativos["Descricao"].tolist())\n\n        fornecedor_id = fornecedor_escolhido.split(" - ")[0]\n        nome_vendedor = fornecedores.loc[fornecedores["FornecedorID"] == fornecedor_id, "Vendedor"].iloc[0]\n\n        dados_cotacao = cotacoes[cotacoes["CotacaoID"] == cotacao_escolhida].iloc[0]\n        itens_filtrados = itens[itens["CotacaoID"] == cotacao_escolhida].merge(produtos, on="ProdutoID", how="left")\n\n        if itens_filtrados.empty:\n            st.info("Esta cotação ainda não tem itens.")\n        else:\n            linhas_produtos = []\n            linhas_resposta = []\n            for _, row in itens_filtrados.iterrows():\n                linha = f"{row[\'ProdutoID\']} - {descricao_produto(row)} - Qtd: {row[\'QuantidadeDesejada\']}"\n                linhas_produtos.append(linha)\n                linhas_resposta.append(f"{row[\'ProdutoID\']} - R$")\n\n            mensagem = f"""Bom dia, {nome_vendedor}!\n\nSegue cotação do Supermercado Marialva.\n\nPor favor, responder com o código e o valor.\nCaso não tenha o produto, responder com NT.\n\nCotação: {cotacao_escolhida}\nPrazo: {dados_cotacao[\'Prazo\']}\n\nItens:\n{chr(10).join(linhas_produtos)}\n\nFormato de resposta:\n{chr(10).join(linhas_resposta)}\n\nObrigado."""\n\n            st.text_area("Copie esta mensagem e envie no WhatsApp:", mensagem, height=400)\n\n# =========================\n# LANÇAR RESPOSTAS INDIVIDUAL\n# =========================\n\nelif menu == "Lançar Respostas":\n    st.header("💰 Lançar Respostas dos Fornecedores")\n\n    if cotacoes.empty:\n        st.warning("Crie uma cotação primeiro.")\n    elif fornecedores.empty:\n        st.warning("Cadastre fornecedores primeiro.")\n    elif produtos.empty:\n        st.warning("Cadastre produtos primeiro.")\n    else:\n        with st.form("form_resposta"):\n            cotacao_escolhida = st.selectbox("Cotação", cotacoes["CotacaoID"].tolist())\n            fornecedores_desc = fornecedores.copy()\n            fornecedores_desc["Descricao"] = fornecedores_desc["FornecedorID"].astype(str) + " - " + fornecedores_desc["Vendedor"].astype(str)\n            fornecedor_escolhido = st.selectbox("Fornecedor", fornecedores_desc["Descricao"].tolist())\n            fornecedor_id = fornecedor_escolhido.split(" - ")[0]\n\n            itens_da_cotacao = itens[itens["CotacaoID"] == cotacao_escolhida].copy()\n            if itens_da_cotacao.empty:\n                st.warning("Esta cotação ainda não tem itens.")\n                produto_id = None\n            else:\n                produtos_disponiveis = itens_da_cotacao.merge(produtos, on="ProdutoID", how="left")\n                produtos_disponiveis["DescricaoCompleta"] = produtos_disponiveis.apply(lambda row: f"{row[\'ProdutoID\']} - {descricao_produto(row)}", axis=1)\n                produto_escolhido = st.selectbox("Produto", produtos_disponiveis["DescricaoCompleta"].tolist())\n                produto_id = produto_escolhido.split(" - ")[0]\n\n            tem_produto = st.selectbox("Tem produto?", ["Sim", "Não"])\n            preco = st.number_input("Preço", min_value=0.0, step=0.01, format="%.2f")\n            observacao = st.text_input("Observação")\n            salvar_resposta = st.form_submit_button("Salvar resposta")\n\n            if salvar_resposta and produto_id:\n                preco_final = preco if tem_produto == "Sim" else None\n                respostas, acao = upsert_resposta(respostas, cotacao_escolhida, fornecedor_id, produto_id, preco_final, tem_produto, observacao.strip())\n                salvar("respostas", respostas)\n                st.success(f"Resposta {acao} com sucesso.")\n                st.rerun()\n\n    st.subheader("Respostas cadastradas")\n    st.dataframe(respostas, use_container_width=True)\n\n# =========================\n# IMPORTAR RESPOSTA WHATSAPP EM BLOCO\n# =========================\n\nelif menu == "Importar Resposta WhatsApp":\n    st.header("📥 Importar Resposta do WhatsApp")\n    st.caption("Cole a resposta do vendedor no formato: PROD001 - 4,20 ou PROD001 - NT")\n\n    if cotacoes.empty or fornecedores.empty or itens.empty:\n        st.warning("Você precisa ter cotação, fornecedor e itens cadastrados antes de importar respostas.")\n    else:\n        cotacao_escolhida = st.selectbox("Cotação", cotacoes["CotacaoID"].tolist())\n        fornecedores_desc = fornecedores.copy()\n        fornecedores_desc["Descricao"] = fornecedores_desc["FornecedorID"].astype(str) + " - " + fornecedores_desc["Vendedor"].astype(str)\n        fornecedor_escolhido = st.selectbox("Fornecedor", fornecedores_desc["Descricao"].tolist())\n        fornecedor_id = fornecedor_escolhido.split(" - ")[0]\n\n        texto_resposta = st.text_area(\n            "Cole aqui a resposta do WhatsApp",\n            height=250,\n            placeholder="PROD001 - 4,20\\nPROD002 - 9,15\\nPROD003 - NT"\n        )\n\n        if st.button("Interpretar e salvar respostas"):\n            itens_validos = set(itens[itens["CotacaoID"] == cotacao_escolhida]["ProdutoID"].astype(str))\n            linhas = [linha.strip() for linha in texto_resposta.splitlines() if linha.strip()]\n\n            salvas = 0\n            atualizadas = 0\n            erros = []\n            preview = []\n\n            for linha in linhas:\n                partes = re.split(r"\\s*[-:;]\\s*", linha, maxsplit=1)\n                if len(partes) < 2:\n                    erros.append(f"Não entendi a linha: {linha}")\n                    continue\n\n                produto_id = partes[0].strip().upper()\n                valor = partes[1].strip()\n\n                if produto_id not in itens_validos:\n                    erros.append(f"{produto_id} não está dentro da cotação {cotacao_escolhida}.")\n                    continue\n\n                if valor.upper() in ["NT", "N/T", "NÃO TEM", "NAO TEM", "SEM", "SEM ESTOQUE"]:\n                    tem_produto = "Não"\n                    preco = None\n                else:\n                    preco = preco_para_float(valor)\n                    if preco is None:\n                        erros.append(f"Preço inválido na linha: {linha}")\n                        continue\n                    tem_produto = "Sim"\n\n                respostas, acao = upsert_resposta(respostas, cotacao_escolhida, fornecedor_id, produto_id, preco, tem_produto, "Importado do WhatsApp")\n                if acao == "criada":\n                    salvas += 1\n                else:\n                    atualizadas += 1\n\n                preview.append({\n                    "ProdutoID": produto_id,\n                    "TemProduto": tem_produto,\n                    "Preco": "" if preco is None else moeda(preco),\n                    "Ação": acao,\n                })\n\n            salvar("respostas", respostas)\n\n            if preview:\n                st.success(f"Importação concluída: {salvas} respostas novas e {atualizadas} atualizadas.")\n                st.dataframe(pd.DataFrame(preview), use_container_width=True)\n\n            if erros:\n                st.warning("Algumas linhas não foram importadas:")\n                for erro in erros:\n                    st.write(f"- {erro}")\n\n# =========================\n# COMPARATIVO\n# =========================\n\nelif menu == "Comparativo":\n    st.header("🏆 Comparativo de Menor Preço")\n\n    if respostas.empty:\n        st.info("Nenhuma resposta lançada ainda.")\n    else:\n        cotacoes_disponiveis = respostas["CotacaoID"].drop_duplicates().tolist()\n        cotacao_escolhida = st.selectbox("Escolha a cotação", cotacoes_disponiveis)\n        resultado = preparar_comparativo(respostas, produtos, fornecedores, cotacao_escolhida)\n\n        if resultado.empty:\n            st.info("Ainda não há preços válidos para comparar nesta cotação.")\n        else:\n            visual = formatar_tabela_moeda(resultado, ["MenorPreco", "MaiorPreco", "EconomiaUnitaria"])\n            st.dataframe(visual, use_container_width=True)\n            col1, col2 = st.columns(2)\n            col1.metric("Produtos com vencedor", len(resultado))\n            col2.metric("Economia potencial unitária total", moeda(resultado["EconomiaUnitaria"].sum()))\n\n# =========================\n# PEDIDO FINAL\n# =========================\n\nelif menu == "Pedido Final":\n    st.header("🧾 Pedido Final por Fornecedor")\n    st.caption("Gera uma lista de compra baseada nos vencedores do comparativo.")\n\n    if respostas.empty:\n        st.info("Nenhuma resposta lançada ainda.")\n    else:\n        cotacoes_disponiveis = respostas["CotacaoID"].drop_duplicates().tolist()\n        cotacao_escolhida = st.selectbox("Escolha a cotação", cotacoes_disponiveis)\n        resultado = preparar_comparativo(respostas, produtos, fornecedores, cotacao_escolhida)\n\n        if resultado.empty:\n            st.info("Ainda não há preços válidos para gerar pedido.")\n        else:\n            itens_cot = itens[itens["CotacaoID"] == cotacao_escolhida][["ProdutoID", "QuantidadeDesejada"]]\n            pedido = resultado.merge(itens_cot, on="ProdutoID", how="left")\n            pedido["QuantidadeDesejada"] = pd.to_numeric(pedido["QuantidadeDesejada"], errors="coerce").fillna(0)\n            pedido["TotalEstimado"] = pedido["MenorPreco"] * pedido["QuantidadeDesejada"]\n\n            total_geral = pedido["TotalEstimado"].sum()\n            st.metric("Total estimado do pedido", moeda(total_geral))\n\n            for fornecedor, grupo in pedido.groupby("FornecedorVencedor"):\n                st.subheader(f"Pedido para {fornecedor}")\n                visual = grupo[["ProdutoID", "DescricaoProduto", "QuantidadeDesejada", "MenorPreco", "TotalEstimado"]].copy()\n                visual = visual.rename(columns={"MenorPreco": "Preço", "DescricaoProduto": "Produto"})\n                st.dataframe(formatar_tabela_moeda(visual, ["Preço", "TotalEstimado"]), use_container_width=True)\n\n                linhas = []\n                for _, row in grupo.iterrows():\n                    linhas.append(f"- {row[\'DescricaoProduto\']} | Qtd: {int(row[\'QuantidadeDesejada\'])} | Preço: {moeda(row[\'MenorPreco\'])}")\n\n                mensagem = f"""Bom dia, {fornecedor}!\n\nSegue pedido do Supermercado Marialva referente à cotação {cotacao_escolhida}:\n\n{chr(10).join(linhas)}\n\nPor favor, confirmar disponibilidade, valor e prazo de entrega.\nObrigado."""\n                st.text_area(f"Mensagem para WhatsApp — {fornecedor}", mensagem, height=220, key=f"pedido_{fornecedor}")\n\n# =========================\n# BACKUPS\n# =========================\n\nelif menu == "Backups":\n    st.header("💾 Backups")\n    st.caption("Crie uma cópia de segurança dos arquivos CSV atuais.")\n\n    if st.button("Criar backup agora"):\n        pasta = fazer_backup_manual()\n        st.success(f"Backup criado em: {pasta}")\n\n    st.subheader("Backups existentes")\n    if os.path.exists(PASTA_BACKUPS):\n        backups = sorted(os.listdir(PASTA_BACKUPS), reverse=True)\n        if backups:\n            st.write(backups)\n        else:\n            st.info("Nenhum backup criado ainda.")\n\n# =========================\n# VER BASES\n# =========================\n\nelif menu == "Ver Bases":\n    st.header("🗂️ Bases do Sistema")\n\n    aba = st.selectbox("Escolha a base", list(ARQUIVOS.keys()))\n    st.dataframe(carregar(aba), use_container_width=True)\n'

